// Parse production order from Notion page properties
const page = $input.first().json;
const props = page.properties || {};

// Extract production order fields
const productionOrder = {
  production_order_id: props['Order ID']?.rich_text?.[0]?.plain_text || `PO-${Date.now()}`,
  client: props['Client']?.select?.name || 'Unknown',
  project_name: props['Project']?.title?.[0]?.plain_text || 'Untitled',
  format: props['Format']?.select?.name || '16:9 cinematic commercial',
  quality_tier: props['Quality']?.select?.name || 'cinematic',
  voiceover_script: props['Script']?.rich_text?.[0]?.plain_text || '',
  brand_profile_id: props['Brand']?.select?.name || 'poptechstudio',
  notion_page_id: page.id,
  shots: [],
  delivery_platforms: ['youtube', 'instagram_reels', 'tiktok'],
};

// Parse shots from a JSON field or child pages
const shotsJson = props['Shots JSON']?.rich_text?.[0]?.plain_text;
if (shotsJson) {
  try { productionOrder.shots = JSON.parse(shotsJson); } catch(e) {}
}

return [{ json: productionOrder }];

// Assemble cinematic prompt from RAG results
const shot = $('Split Into Shots').first().json;
const camera = $('RAG: Camera Preset').first().json?.result?.[0]?.payload || {};
const lighting = $('RAG: Lighting Preset').first().json?.result?.[0]?.payload || {};

// Multi-shot cinematic prompt assembly (SOP Step 14A)
const cameraFragment = camera.prompt_fragment || `shot on ARRI Alexa 35 with Cooke S7i 50mm at f/1.4`;
const lightingFragment = lighting.prompt_fragment || `warm tungsten 3200K, key light 45 degrees`;

const assembledPrompt = [
  shot.description,
  cameraFragment,
  lightingFragment,
  'Photo real, natural framing.'
].join(', ');

return [{
  json: {
    ...shot,
    assembled_prompt: assembledPrompt,
    camera_preset: camera,
    lighting_preset: lighting,
  }
}];

// Log generation cost
const shot = $json;
const durationSec = shot.duration_seconds || 5;
const costPerSec = 0.10; // Seedance 2.0 estimate
const cost = durationSec * costPerSec;

return [{
  json: {
    ...shot,
    generation_cost: cost,
    generation_service: 'fal.ai_seedance2.0',
    generation_timestamp: new Date().toISOString(),
  }
}];

// QC checkpoint: shot generation complete
const shot = $json;
return [{
  json: {
    checkpoint: 'generation_complete',
    shot_id: shot.shot_id,
    timestamp: new Date().toISOString(),
    cost: shot.generation_cost,
    status: 'pass',
  }
}];

// Aggregate all shots back together
const allShots = $input.all().map(item => item.json);
const totalCost = allShots.reduce((sum, s) => sum + (s.generation_cost || 0), 0);

return [{
  json: {
    shots: allShots,
    total_generation_cost: totalCost,
    shot_count: allShots.length,
  }
}];

// ElevenLabs voice synthesis stub
// In production: call ElevenLabs MCP or API
const order = $json;

return [{
  json: {
    ...order,
    voiceover_path: `/tmp/cinema_studio/${order.production_order_id || 'PO-STUB'}/voiceover.mp3`,
    voiceover_cost: 0.01,
    voiceover_service: 'elevenlabs',
  }
}];

// Remotion composition — calls CLI to render
// Template: PopTech (from Task 4.5) for branded, Generic for client
const order = $json;
const templateId = order.brand_profile_id === 'poptechstudio' ? 'PopTech' : 'Generic';

// Build props JSON for Remotion
const props = {
  clips: (order.shots || []).map(s => ({
    videoUrl: s.output_path || '',
    duration: s.duration_seconds || 5,
  })),
  audioUrl: order.voiceover_path || '',
  title: order.project_name || 'Production',
  ctaButton: { text: 'Learn More' },
};

return [{
  json: {
    ...order,
    remotion_template: templateId,
    remotion_props: props,
    remotion_command: `npx remotion render src/index.ts ${templateId} --props='${JSON.stringify(props)}' --output /tmp/cinema_studio/${order.production_order_id}/composite.mp4`,
  }
}];

// FFmpeg color grade + LUT pipeline
const order = $json;
const lut = order.brand_profile_id === 'poptechstudio' ? 'kodak_vision3_500t' : 'neutral_normalize';

return [{
  json: {
    ...order,
    color_grade_command: `python tools/color_grade.py /tmp/cinema_studio/${order.production_order_id}/composite.mp4 --chain "neutral_normalize,${lut}" --grain 0.12 --vignette 0.25 --output /tmp/cinema_studio/${order.production_order_id}/graded.mp4`,
    lut_applied: lut,
  }
}];

// Platform encoding — generate 3 aspect ratio variants
const order = $json;
const poId = order.production_order_id || 'PO-STUB';

const encodes = [
  { platform: 'youtube', aspect: '16:9', res: '1920x1080', file: `final_16x9.mp4` },
  { platform: 'instagram_reels', aspect: '9:16', res: '1080x1920', file: `final_9x16.mp4` },
  { platform: 'tiktok', aspect: '1:1', res: '1080x1080', file: `final_1x1.mp4` },
];

return [{
  json: {
    ...order,
    platform_encodes: encodes.map(e => ({
      ...e,
      path: `/tmp/cinema_studio/${poId}/${e.file}`,
      command: `ffmpeg -y -i /tmp/cinema_studio/${poId}/graded.mp4 -vf "scale=${e.res}:force_original_aspect_ratio=decrease,pad=${e.res}:(ow-iw)/2:(oh-ih)/2:black" -c:v libx264 -crf 18 -c:a aac -b:a 192k /tmp/cinema_studio/${poId}/${e.file}`,
    })),
  }
}];

// Video publisher dispatch — stub for Task 4.6
const order = $json;
const encodes = order.platform_encodes || [];

return [{
  json: {
    ...order,
    publish_status: 'ready_for_dispatch',
    publish_targets: encodes.map(e => ({
      platform: e.platform,
      file: e.path,
      status: 'queued',
    })),
  }
}];

// Cost reconciliation
const order = $json;
const genCost = order.total_generation_cost || 0;
const voCost = order.voiceover_cost || 0;
const totalCost = genCost + voCost;

return [{
  json: {
    production_order_id: order.production_order_id,
    client: order.client,
    project_name: order.project_name,
    total_cost: totalCost,
    breakdown: {
      generation: genCost,
      voiceover: voCost,
      compositing: 0,
      color_grading: 0,
      encoding: 0,
    },
    shot_count: order.shot_count || 0,
    cost_per_shot: order.shot_count ? (totalCost / order.shot_count).toFixed(2) : '0',
    timestamp: new Date().toISOString(),
  }
}];

// Final summary for Slack notification
const cost = $json;
return [{
  json: {
    text: `*Commercial Production Complete* \n` +
      `Order: ${cost.production_order_id}\n` +
      `Client: ${cost.client}\n` +
      `Project: ${cost.project_name}\n` +
      `Shots: ${cost.shot_count}\n` +
      `Total Cost: $${cost.total_cost.toFixed(2)}\n` +
      `Cost/Shot: $${cost.cost_per_shot}\n` +
      `Status: Ready for QC Review`,
  }
}];
